import { createStore } from "./lib/store.js";
import { createMailer } from "./lib/mailer.js";
import { authRouter, sessionFromReq, requireAuth } from "./lib/auth.js";

const store = await createStore();
const mailer = await createMailer();

app.use(authRouter({ store, mailer }));   // adds /api/login, /verify, /api/confirm, /api/logout, /api/me

// protect a route:
app.post("/api/things", requireAuth(store), (req, res) => {
  res.json({ ok: true, you: req.user.email });
});

// or check anywhere:
const session = await sessionFromReq(store, req);   // { email } | null
